import{_ as s,c as a,o as i,aj as e}from"./chunks/framework.CLcCQpUA.js";const g=JSON.parse('{"title":"💻 macOS( mac 操作系统) 部署","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/mac-required-reading.md","filePath":"deploy/mac-required-reading.md"}'),t={name:"deploy/mac-required-reading.md"},l=e(`<h1 id="💻-macos-mac-操作系统-部署" tabindex="-1">💻 macOS( mac 操作系统) 部署 <a class="header-anchor" href="#💻-macos-mac-操作系统-部署" aria-label="Permalink to &quot;💻 macOS( mac 操作系统) 部署&quot;">​</a></h1><h2 id="📑-说明" tabindex="-1">📑 说明 <a class="header-anchor" href="#📑-说明" aria-label="Permalink to &quot;📑 说明&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">v2.4.0-beta 之后的绿色包均转为套壳的 <code>uv tool</code></p><hr><p>也推荐干脆直接使用 <a href="/ComicGUISpider/deploy/quick-start.html#1-下载--部署">uv tool方式部署安装</a></p></div><h2 id="⛵️-绿色包操作" tabindex="-1">⛵️ 绿色包操作 <a class="header-anchor" href="#⛵️-绿色包操作" aria-label="Permalink to &quot;⛵️ 绿色包操作&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">mac 由于认证签名收费，打包派发的 app 初次打开会有限制，正确操作如下</p><ol><li>对 app 右键打开，报错不要丢垃圾篓，直接取消</li><li>再对 app 右键打开，此时弹出窗口有打开选项，能打开了</li><li>后续就能双击打开，不用右键打开了</li></ol></div><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">解析说明</th></tr></thead><tbody><tr><td style="text-align:center;">1. 初始化</td><td style="text-align:left;">解压后初次运行<code>CGS.app</code>时（点击app前阅读上方签名收费的提示）<br>检测没 <code>brew</code>、<code>uv</code> 环境的话，会在终端指引安装此两，然后安装<code>CGS</code></td></tr><tr><td style="text-align:center;">2. 常规运行</td><td style="text-align:left;">以后打开会检测<code>uv tool dir --bin</code>里有没<code>cgs</code>可执行，有则直接打开</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">换源相关</p><p>初始化中带 pypi 字眼相关的失败的话可尝试进行换源，执行下方的命令<br> 命令中 <code>...-s 1</code> 最后的数字序号对应 pypi 国内源，序号参考 <a href="/ComicGUISpider/config/#pypi源-pypi-source">序号映射</a></p></div><div class="tip custom-block"><p class="custom-block-title"><code>CGS.app</code>实际执行的命令</p><p><strong>单独 初始化/环境更新/CGS更新等 执行命令：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gitee.com/json_eri/ComicGUISpider/raw/GUI/deploy/launcher/mac/init.bash</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><p><em><strong>根据终端提示操作</strong></em></p></div><div class="warning custom-block"><p class="custom-block-title"><em><strong>源码根目录</strong></em> (执行以下命令获取)</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tool dir)/comicguispider/Lib/site-packages&quot;</span></span></code></pre></div><p>所有文档中由<code>site-packages</code>开始的目录的<br> 包括此mac部署说明，主说明README，release页面，issue的等等等等，<br><code>site-packages</code>目录就是命令得出的源码根目录</p></div><h2 id="🔰-其他" tabindex="-1">🔰 其他 <a class="header-anchor" href="#🔰-其他" aria-label="Permalink to &quot;🔰 其他&quot;">​</a></h2><h3 id="cgs-app-无法运行就直接用-uv-编译的" tabindex="-1">CGS.app 无法运行就直接用 uv 编译的 <a class="header-anchor" href="#cgs-app-无法运行就直接用-uv-编译的" aria-label="Permalink to &quot;CGS.app 无法运行就直接用 uv 编译的&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cgs</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comicguispider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cgs</span></span></code></pre></div><h3 id="bug-report-提交报错-issue" tabindex="-1">bug report / 提交报错 issue <a class="header-anchor" href="#bug-report-提交报错-issue" aria-label="Permalink to &quot;bug report / 提交报错 issue&quot;">​</a></h3><p>macOS上运行软件出错需要提issue时，除系统选<code>macOS</code>外，还需描述加上系统版本与架构<br> （开发者测试开发环境为<code>macOS Sonoma(14) / x86_64</code>）</p><div class="tip custom-block"><p class="custom-block-title">获取架构命令</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;import platform; print(platform.machine())&quot;</span></span></code></pre></div></div>`,15),p=[l];function o(c,n,d,h,r,k){return i(),a("div",null,p)}const b=s(t,[["render",o]]);export{g as __pageData,b as default};
